import { forwardRef, useRef } from 'react';
import { useTooltip, type TooltipProp } from '../../hooks/useTooltip';

export interface O9ButtonLinkProps extends Omit<React.AnchorHTMLAttributes<HTMLAnchorElement>, 'href'> {
  variant?: 'primary' | 'secondary' | 'tertiary' | 'outline' | 'danger';
  size?: 'sm' | 'md' | 'lg';
  label: string;
  href: string;
  icon?: string;
  isDisabled?: boolean;
  isFullWidth?: boolean;
  isLoading?: boolean;
  tooltip?: TooltipProp;
}

const O9ButtonLink = forwardRef<HTMLAnchorElement, O9ButtonLinkProps>(
  function O9ButtonLink(
    {
      variant = 'primary',
      size = 'md',
      label,
      href,
      icon,
      isDisabled = false,
      isFullWidth = false,
      isLoading = false,
      tooltip,
      target,
      rel,
      className,
      onClick,
      ...rest
    },
    ref
  ) {
    const internalRef = useRef<HTMLAnchorElement | null>(null);

    useTooltip({ triggerRef: internalRef, tooltip });
    const needsRel = target === '_blank';
    const effectiveRel = needsRel
      ? rel ?? 'noopener noreferrer'
      : rel;

    const classes = [
      'o9ds-btn',
      `o9ds-btn--${variant}`,
      `o9ds-btn--${size}`,
      isFullWidth ? 'o9ds-btn--full-width' : '',
      isDisabled ? 'is-disabled' : '',
      isLoading ? 'loading' : '',
      className ?? '',
    ]
      .filter(Boolean)
      .join(' ');

    const blocked = isDisabled || isLoading;

    const handleClick = (e: React.MouseEvent<HTMLAnchorElement>) => {
      if (blocked) {
        e.preventDefault();
        e.stopPropagation();
        return;
      }
      onClick?.(e);
    };

    const mergeRefs = (node: HTMLAnchorElement | null) => {
      internalRef.current = node;
      if (typeof ref === 'function') ref(node);
      else if (ref) ref.current = node;
    };

    return (
      <a
        ref={mergeRefs}
        href={isDisabled ? undefined : href}
        target={isDisabled ? undefined : target}
        rel={isDisabled ? undefined : effectiveRel}
        className={classes}
        aria-disabled={isDisabled ? true : undefined}
        aria-busy={isLoading ? true : undefined}
        tabIndex={isDisabled ? 0 : undefined}
        onClick={handleClick}
        {...rest}
      >
        {icon && (
          <span
            className={`o9ds-btn__ico o9con o9con-${icon}`}
            aria-hidden="true"
          />
        )}
        <span className="o9ds-btn__lbl">{label}</span>
      </a>
    );
  }
);

export default O9ButtonLink;
